import { useMemo } from "react";
import { Field } from "react-final-form";
import { useNavigate } from "react-router-dom";
import { InputField } from "../../../common/InputText";
import { Condition, Error, required } from "../../../common/Utilitis";
import female from "../../assets/images/icons/female.png";
import male from "../../assets/images/icons/male.png";
import AuthService from "../../services/auth.service";
import Wizard from "./Wizard";
// import { Country, City } from "country-state-city";
import Select from "react-select";
import CountryCity from "../../../common/Country-City";
function RegistrationSteps(props) {
  const navigate = useNavigate();
  const optionsCountryList = useMemo(() => CountryCity.getCountriesList(), []);
  console.log(
    "🚀 ~ file: registationSteps.jsx ~ line 16 ~ RegistrationSteps ~ CountryCity.getCountriesList()",
    CountryCity.getCountriesList()
  );

  const onSubmit = async (values) => {
    //window.alert(JSON.stringify(values, 0, 2));
    //setIsLoading(true);
    // await sleep(1500);
    const formValues = { ...props.values, ...values };
    console.log(`onSubmit :: ${JSON.stringify(formValues, 0, 2)}`);

    const response = await AuthService.register({
      email: formValues.email,
      password: formValues.password,
      firstName: formValues.firstName,
      lastName: formValues.lastName,
      phone: formValues.mobile,
      gender: formValues.gender,
      nationality: formValues.nationality,
      countryOfResidence: formValues.countryOfResidence,
      cityOfResidence: formValues.cityOfResidence,
      dateOfBirth: `${formValues.year}-${formValues.month.padStart(
        2,
        "0"
      )}-${formValues.day.padStart(2, "0")}`,
    });
    //setMessage(!!response.message && response.message);
    //setIsLoading(false);

    if (!!!response.success && !response.success) {
      // props.OnError({
      //   messgeType: "error",
      //   messageTitle: "Warning",
      //   messageBody: !!response.message && response.message,
      // });
      props.OnError(!!response.message && response.message);
    } else {
      navigate("/login", {
        ...values,
        state: {
          preStatus: "success",
          loginBoldMsg: "An email was sent to you!",
          loginMsg: "please check your inbox to complete registration",
        },
      });
    }
  };

  function generateArrayOfYears() {
    const max = new Date().getFullYear() - 10;
    const min = 1920;
    let years = [];
    for (let i = min; i < max; i++) {
      years.push(i);
    }
    return years;
  }
  const months = [
    { text: "Jan", value: 1 },
    { text: "Feb", value: 2 },
    { text: "Mar", value: 3 },
    { text: "Apr", value: 4 },
    { text: "May", value: 5 },
    { text: "Jun", value: 6 },
    { text: "Jul", value: 7 },
    { text: "Aug", value: 8 },
    { text: "Sep", value: 9 },
    { text: "Oct", value: 10 },
    { text: "Nov", value: 11 },
    { text: "Dec", value: 12 },
  ];
  const getDays = (month) => {
    const min = 1;
    let max = 31;
    if (month === "4" || month === "6" || month === "9" || month === "11") max = 30;
    if (month === "2") max = 28;
    let monthDays = [];
    for (let i = min; i <= max; i++) {
      monthDays.push(i);
    }
    return monthDays;
  };
  let days = getDays("1");
  const initialValues = {
    gender: "",
    year: "",
    month: "",
    day: "",
    nationality: "",
    countryOfResidence: "",
    cityOfResidence: "",
  };
  const ReactSelectAdapter = ({ input, ...rest }) => (
    <Select {...input} {...rest} searchable />
  );

  const SelectCities = ({ countery, children }) => (
    <Field name={countery} subscription={{ value: true }}>
      {({ input: { value } }) => (
        <>
          {CountryCity.getCitiesOfCountry(value).map((val, index) => (
            <option key={index} value={val.name}>
              {val.name}
            </option>
          ))}
        </>
      )}
    </Field>
  );

  const WizatForm = () => (
    <Wizard initialValues={initialValues} onSubmit={onSubmit}>
      <Wizard.Page
        validate={(values) => {
          const errors = {};
          if (!values.gender) {
            errors.gender = required;
          }
          return errors;
        }}
      >
        <div className="text-center mt-2">
          <h3 className="mt-3 mb-5">Select Your Gender</h3>
          <Error name={"gender"} showerrorbeside="true" />
        </div>
        <div className="select-gender-col mb-2" style={{ textAlign: "center" }}>
          <div className="row justify-content-center">
            <div className="col-sm-6">
              <Field
                id="male_radio"
                name="gender"
                value="Male"
                type="radio"
                component={InputField}
                hideerror="true"
              />
              <label htmlFor="male_radio">
                <span className="gender-icon">
                  <img src={male} style={{ borderRadius: "5px" }}></img>
                </span>
              </label>
            </div>
            <div className="col-sm-6">
              <Field
                id="female_radio"
                name="gender"
                value="Female"
                type="radio"
                component={InputField}
                hideerror="true"
              />
              <label htmlFor="female_radio">
                <span className="gender-icon">
                  <img src={female} style={{ borderRadius: "5px" }}></img>
                </span>
              </label>
            </div>
          </div>
        </div>
      </Wizard.Page>
      <Wizard.Page
        validate={(values) => {
          const errors = {};
          if (!values.year) {
            errors.year = "Required";
          }
          if (!values.month) {
            errors.month = "Required";
          }
          if (!values.day) {
            errors.day = "Required";
          }
          return errors;
        }}
      >
        <div className="text-center mt-2">
          <h3 className="mt-3 mb-5">Date of Birth</h3>
        </div>
        <div className="row">
          <div className="form-group col-md-4">
            <label>Year</label>
            <Field
              name="year"
              className="form-control select"
              component="select"
              showerrorbeside="true"
              style={{ minWidth: "88px" }}
            >
              <option />
              {generateArrayOfYears().map((val, index) => (
                <option key={index} value={val}>
                  {val}
                </option>
              ))}
            </Field>
            <Error name={"year"} showerrorbeside="true" />
          </div>
          <div className="col-md-4 form-group">
            <label>Month</label>
            <Field
              name="month"
              className="form-control select"
              component="select"
              showerrorbeside="true"
              // onChange={(val) => days =getDays(val.target.value)}
            >
              <option />
              {months.map((val, index) => (
                <option key={index} value={val.value}>
                  {val.text}
                </option>
              ))}
            </Field>
            <Error name={"month"} showerrorbeside="true" />
          </div>
          <div className="col-md-4  form-group">
            <label>Day</label>
            <Field
              name="day"
              className="form-control select"
              component="select"
              showerrorbeside="true"
              required={required}
            >
              <Condition when={"month"} is="1">
                {getDays("1").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="2">
                {getDays("2").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="3">
                {getDays("3").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="4">
                {getDays("4").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="5">
                {getDays("5").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="6">
                {getDays("6").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="7">
                {getDays("7").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="8">
                {getDays("8").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="9">
                {getDays("9").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="10">
                {getDays("10").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="11">
                {getDays("11").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
              <Condition when={"month"} is="12">
                {getDays("12").map((val, index) => (
                  <option key={index} value={val}>
                    {val}
                  </option>
                ))}
              </Condition>
            </Field>
            <Error name={"day"} showerrorbeside="true" />
          </div>
        </div>
      </Wizard.Page>
      <Wizard.Page
        validate={(values) => {
          const errors = {};
          if (!values.nationality) {
            errors.nationality = required;
          }
          if (!values.countryOfResidence) {
            errors.countryOfResidence = required;
          }
          if (!values.cityOfResidence) {
            errors.cityOfResidence = required;
          }
          return errors;
        }}
      >
        <>
          <div className="text-center mt-2">
            <h3 className="mt-3 mb-5">Nationality and Location</h3>
          </div>
          <div className="form-group">
            <label>Nationality</label>
            <Field
              name="nationality"
              className="form-control select"
              component="select"
              showerrorbeside="true"
            >
              <option value="">Select Your Nationality</option>
              {optionsCountryList.map((val, index) => (
                <option key={index} value={val.isoCode}>
                  {val.name}
                </option>
              ))}
            </Field>
            {/* <Field
              name="nationality"
              component={ReactSelectAdapter}
              options={optionsCountryList.map((val, index) => ({
                value: val.isoCode,
                label: val.name,
              }))}
            /> */}
            <Error name={"nationality"} showerrorbeside="true" />
          </div>
          <div className="form-group">
            <label>Country of Residence</label>
            <Field name="countryOfResidence" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                      // console.log(e.target.value);
                      //console.table(City.getCitiesOfCountry(e.target.value))
                    }}
                  >
                    <option value="">Select Your Country of Residence</option>
                    {optionsCountryList.map((val, index) => (
                      <option key={index} value={val.isoCode}>
                        {val.name}
                      </option>
                    ))}
                  </select>
                );
              }}
            </Field>
            <Error name={"countryOfResidence"} showerrorbeside="true" />
          </div>
          <div className="form-group">
            <label>City of Residence</label>
            <Field name="cityOfResidence" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                    }}
                  >
                    <option value="">Select Your Country of Residence</option>
                    <SelectCities countery="countryOfResidence" />
                  </select>
                );
              }}
            </Field>
            <Error name={"cityOfResidence"} showerrorbeside="true" />
          </div>
        </>
      </Wizard.Page>
    </Wizard>
  );

  return <WizatForm />;
}
export default RegistrationSteps;
